var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와하하, 쌤이랑 개인 면담 시간이라니! 이런 호감도 이벤트는 놓칠 수 없다구요!","JPN":"わはは、先生との個人面談だって！　こんな好感度イベント見逃すわけにはいかないですよね！","ENG":"Wahaha! I got Teach all to myself? Wouldn't miss this for the world!","TWN":"哇哈哈，是和老師一對一談話的時間欸！這種好感度活動當然不能錯過囉！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"물론, 쌤을 향한 제 호감도는 이미 만땅이지만! 헤헤.","JPN":"もちろん、先生に対する好感度はすでにマックスですけど！　へへ。","ENG":"But you know, my intimacy for ya is already about to burst! Hehe!","TWN":"不過我對老師的好感度早就達到天花板啦！嘿嘿。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어라? 쌤, 그런데 이건 뭐예요? 무슨 계약서 같은데?","JPN":"え？　先生、それでこれは何ですか？　契約書か何かに見えますけど？","ENG":"Huh? What's that, Teach? A contract?","TWN":"嗯？不過老師，這是什麼？好像是什麼合約欸？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엣!? 설마 이건 말로만 듣던 조, 종신 계약서!?","JPN":"ええっ！？　まさか、これが噂のしゅ、終身契約ですか！？","ENG":"Huh?! I-is that what I think it is?! A l-lifetime contract?!","TWN":"難…難道！？這是就是傳聞中的終…終身契約！？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쯧쯧……! 쌤, 그라믄 안 돼요, 그라믄……! 일단, 여긴 학교라고요! 학교!","JPN":"チッチッ……！　先生、ダメですよ、それは……！　ここは学校ですよ、学校！","ENG":"Tsk tsk...! Teach, that ain't right, no sir...! First of all, we're at a school!","TWN":"嘖嘖……！老師，你不可以這樣唄！不可以啦……！這裡是學校欸！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"제가 그동안 쪼매 쌤 놀렸다고 이렇게 공들여서 장난치고 막 그라면 안 돼요~ 안 돼.","JPN":"ウチがこれまで先生をちょっと驚かせたからって、こんな風に念の入ったいたずらするなんて。そんなのダメです。","ENG":"You can't go around prankin' students like that, Teach! Even if I did tease ya a bit.","TWN":"因為我過去常拿老師開點小玩笑，你就精心設計這場惡作劇嗎？你不可以這樣唄，不可以啦～"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자꾸 이러시면…… 저 쌤한테 진짜 콱 고백해버릴 겁니다……? 네!?","JPN":"何度もこういうことすると……ウチ、先生にマジで告白しますよ……？　え！？","ENG":"You keep that up, and... I'm gonna confess my feelings for ya...? Okay?!","TWN":"老師再這樣的話……那我就要真的跟老師告白囉……？嗯！？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"지, 진심이라고요……? 이미 호감도 만땅이라고요……?","JPN":"ま、マジですか……？　もう好感度マックスって……？","ENG":"Y-you're not jokin'...? Y-your intimacy’s full too...?","TWN":"老…老師是認真的嗎……？你對我的好感度也已經達到天花板嗎……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으, 으아아……!?","JPN":"う、うわああ……！？","ENG":"U-uaaah...?!","TWN":"啊啊啊……！？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 잠시만요! 이런 건…… 내 장래 계획에 없었을낀데……?","JPN":"ま、待ってください！　こんなの……ウチの将来の計画にはなかったんやけど……？","ENG":"W-wait! This wasn't... in any of my plans...?","TWN":"先…先等一下！這種事……不在我將來的計畫裡欸……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"무, 물론 앞으로도 자나깨나 쭉 선생님 곁에 있으려고는 했지만……","JPN":"も、もちろんこれからも寝ても覚めても先生の傍にはいようと思ってましたけど……","ENG":"Y-yeah, I was gonna stay by your side no matter what, but...","TWN":"是…是沒錯啦，我是以後也想時時刻刻陪伴在老師身邊……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그건 그거고! 이건 이거라고요!","JPN":"あ、それはそれ！　これはこれです！","ENG":"B-but that's that! And this is this!","TWN":"可是，這是兩碼子事吧！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"알겠어요. 쌤이 그렇게까지 말씀하신다면…… 대신, 조건이 하나 있어요!","JPN":"わかりました。先生がそうまで言うなら……その代わり条件が一つあります！","ENG":"Fine. If ya insist, Teach... But under one condition!","TWN":"好吧，既然是老師開的口……不過我有一個條件！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그게 뭐냐하면…….","JPN":"何かというと……","ENG":"And that's...","TWN":"條件就是……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};